parameters.jsCode:
// ใช้ $input.all() แทน items
const inputItems = $input.all();

// 1. วนลูปเก็บ request_id และ vector ของทุกเล่มมาใส่ Array
const vectorMap = inputItems.map(item => {
  return {
    "request_id": item.json.request_id,
    "vector_text": item.json.vector_text
  }
});

// 2. ส่งออกไปเป็น 1 Item (ที่มี JSON String ก้อนใหญ่)
return {
  json: {
    // ดึง batch_id จากตัวแรก
    batch_id: inputItems[0].json.batch_id,

    // แปลง Array ให้เป็น String เพื่อส่งให้ SQL
    vectors_json: JSON.stringify(vectorMap)
  }
};

const input = $input.all();
return input.map(item => {
  try {
    const rawText = item.json.output;
    // ใช้ Regex ค้นหาจุดเริ่มต้น { และจุดสิ้นสุด } ที่อยู่นอกสุด
    const jsonMatch = rawText.match(/\{[\s\S]*\}/);

    if (jsonMatch) {
      // แปลงข้อความที่ตัดมาได้ให้เป็น Object จริงๆ
      const cleanJson = JSON.parse(jsonMatch[0]);
      return { json: cleanJson };
    }
    throw new Error("No JSON found in output");
  } catch (error) {
    // กรณีที่ AI พ่นอะไรที่พังจริงๆ ให้ส่งค่า Raw ไปตรวจสอบ
    return {
      json: { 
        error: "Parse Error", 
        raw_output: item.json.output 
      }
    };
  }
});

